/**
 * @param {number[]} nums
 * @param {number} target
 * @return {number}
 */
function solve(nums, target) {
    const n = nums.length;
    // Since N is small (up to 40), we can use Meet-in-the-Middle approach
    // or brute force if N were even smaller. With N=40, 2^40 is too large.
    // Meet-in-the-Middle is the standard technique for subset problems when N is around 40.

    const mid = Math.floor(n / 2);
    const nums1 = nums.slice(0, mid);
    const nums2 = nums.slice(mid);

    // 1. Generate all possible XOR sums for the first half (nums1)
    // Map: xor_sum -> minimum number of elements needed to achieve this sum (in nums1)
    const map1 = new Map();
    // Iterate through all 2^mid subsets of nums1
    for (let i = 0; i < (1 << nums1.length); i++) {
        let currentXor = 0;
        let count = 0;
        for (let j = 0; j < nums1.length; j++) {
            if ((i >> j) & 1) {
                currentXor ^= nums1[j];
                count++;
            }
        }
        // Store the minimum count required to achieve currentXor
        if (!map1.has(currentXor) || count < map1.get(currentXor)) {
            map1.set(currentXor, count);
        }
    }

    // 2. Generate all possible XOR sums for the second half (nums2)
    // Map: xor_sum -> minimum number of elements needed to achieve this sum (in nums2)
    const map2 = new Map();
    // Iterate through all 2^(n-mid) subsets of nums2
    for (let i = 0; i < (1 << nums2.length); i++) {
        let currentXor = 0;
        let count = 0;
        for (let j = 0; j < nums2.length; j++) {
            if ((i >> j) & 1) {
                currentXor ^= nums2[j];
                count++;
            }
        }
        // Store the minimum count required to achieve currentXor
        if (!map2.has(currentXor) || count < map2.get(currentXor)) {
            map2.set(currentXor, count);
        }
    }

    // 3. Combine results
    let minRemoved = Infinity;
    let totalElements = n;

    // Iterate through all sums achievable in the first half
    for (const [xor1, count1] of map1.entries()) {
        // We need xor1 ^ xor2 = target
        // This means xor2 must be equal to xor1 ^ target
        const requiredXor2 = xor1 ^ target;

        if (map2.has(requiredXor2)) {
            const count2 = map2.get(requiredXor2);
            // Total selected elements = count1 + count2
            const selectedElements = count1 + count2;
            // Removed elements = Total elements - Selected elements
            const removed = totalElements - selectedElements;

            minRemoved = Math.min(minRemoved, removed);
        }
    }

    if (minRemoved === Infinity) {
        return -1;
    } else {
        return minRemoved;
    }
}

