#include <vector>
#include <cmath>
#include <algorithm>
#include <map>
#include <climits>

using namespace std;

// The problem asks for the minimum number of elements to remove such that the XOR sum 
// of the remaining elements equals 'target'.
// Minimizing removals is equivalent to maximizing the number of selected elements.
// Let S be the set of indices of selected elements. We want to maximize |S| such that XOR_{i in S} nums[i] = target.
// The minimum removals will be N - max(|S|).

// Since N <= 40, we use Meet-in-the-Middle (MITM).
long long solve(std::vector<long long> nums, long long target) {
    int n = nums.size();
    if (n == 0) {
        return (target == 0) ? 0 : -1;
    }

    int mid = n / 2;
    std::vector<long long> nums1(nums.begin(), nums.begin() + mid);
    std::vector<long long> nums2(nums.begin() + mid, nums.end());

    // Map: xor_sum -> maximum number of elements needed to achieve this sum
    // We maximize the count of selected elements.
    std::map<long long, int> map1;

    // Generate all 2^mid subsets for the first half (nums1)
    int n1 = nums1.size();
    for (int i = 0; i < (1 << n1); ++i) {
        long long currentXor = 0;
        int count = 0;
        for (int j = 0; j < n1; ++j) {
            if ((i >> j) & 1) {
                currentXor ^= nums1[j];
                count++;
            }
        }
        // Store the maximum count required to achieve currentXor
        if (map1.find(currentXor) == map1.end() || count > map1[currentXor]) {
            map1[currentXor] = count;
        }
    }

    std::map<long long, int> map2;

    // Generate all 2^(n-mid) subsets for the second half (nums2)
    int n2 = nums2.size();
    for (int i = 0; i < (1 << n2); ++i) {
        long long currentXor = 0;
        int count = 0;
        for (int j = 0; j < n2; ++j) {
            if ((i >> j) & 1) {
                currentXor ^= nums2[j];
                count++;
            }
        }
        // Store the maximum count required to achieve currentXor
        if (map2.find(currentXor) == map2.end() || count > map2[currentXor]) {
            map2[currentXor] = count;
        }
    }

    // Combine results to find the maximum total selected elements
    int maxSelected = -1; // Use -1 to represent "not found yet" since max possible is N

    // Iterate through all sums achievable in the first half
    for (const auto& pair1 : map1) {
        long long xor1 = pair1.first;
        int count1 = pair1.second;

        // We need xor1 ^ xor2 = target => xor2 = xor1 ^ target
        long long requiredXor2 = xor1 ^ target;

        if (map2.count(requiredXor2)) {
            int count2 = map2[requiredXor2];
            // Total selected elements = count1 + count2
            int selectedElements = count1 + count2;

            if (selectedElements > maxSelected) {
                maxSelected = selectedElements;
            }
        }
    }

    if (maxSelected == -1) {
        return -1;
    } else {
        // Minimum removed = Total elements - Maximum selected elements
        return n - maxSelected;
    }
}
