long long solve(std::vector<long long> nums, long long target) {
    int n = nums.size();
    // Since N is up to 40, Meet-in-the-Middle is used.

    int mid = n / 2;
    std::vector<long long> nums1(nums.begin(), nums.begin() + mid);
    std::vector<long long> nums2(nums.begin() + mid, nums.end());

    // Map: xor_sum -> minimum number of elements needed to achieve this sum
    std::map<long long, int> map1;

    // 1. Generate all possible XOR sums for the first half (nums1)
    int n1 = nums1.size();
    for (int i = 0; i < (1 << n1); ++i) {
        long long currentXor = 0;
        int count = 0;
        for (int j = 0; j < n1; ++j) {
            if ((i >> j) & 1) {
                currentXor ^= nums1[j];
                count++;
            }
        }

        // Store the minimum count required to achieve currentXor
        if (map1.find(currentXor) == map1.end() || count < map1[currentXor]) {
            map1[currentXor] = count;
        }
    }

    std::map<long long, int> map2;

    // 2. Generate all possible XOR sums for the second half (nums2)
    int n2 = nums2.size();
    for (int i = 0; i < (1 << n2); ++i) {
        long long currentXor = 0;
        int count = 0;
        for (int j = 0; j < n2; ++j) {
            if ((i >> j) & 1) {
                currentXor ^= nums2[j];
                count++;
            }
        }

        // Store the minimum count required to achieve currentXor
        if (map2.find(currentXor) == map2.end() || count < map2[currentXor]) {
            map2[currentXor] = count;
        }
    }

    // 3. Combine results
    int minRemoved = n + 1; // Initialize to something larger than max possible removals (n)

    // Iterate through all sums achievable in the first half
    for (const auto& pair1 : map1) {
        long long xor1 = pair1.first;
        int count1 = pair1.second;

        // We need xor1 ^ xor2 = target
        // This means xor2 must be equal to xor1 ^ target
        long long requiredXor2 = xor1 ^ target;

        if (map2.count(requiredXor2)) {
            int count2 = map2.at(requiredXor2);

            // Total selected elements = count1 + count2
            int selectedElements = count1 + count2;

            // Removed elements = Total elements - Selected elements
            int removed = n - selectedElements;

