    // We want (xor1 ^ xor2) = target, so xor2 = xor1 ^ target
    int min_selected = INT_MAX;

    for (const auto& pair1 : map1) {
        long long xor1 = pair1.first;
        int count1 = pair1.second;

        long long required_xor2 = xor1 ^ target;

        if (map2.count(required_xor2)) {
            int count2 = map2[required_xor2];

