            int selected_elements = count1 + count2;
            min_selected = std::min(min_selected, selected_elements);
        }
    }

    if (min_selected == INT_MAX) {
        return -1; // Cannot achieve the target XOR sum
    } else {
        // Minimum removed = Total elements - Maximum selected
        return n - min_selected;
    }
